typia/package.json:
{
  "name": "typia",
  "version": "13.1.19",
  "description": "Superfast runtime validators with only one line",
  "main": "lib/index.js",
  "exports": {
    ".": "./lib/index.js",
    "./lib/module": "./lib/index.js",
    "./lib/transform": "./lib/transform.js",
    "./lib/internal/*": "./lib/internal/*.js",
    "./package.json": "./package.json"
  },
  "bin": {
    "typia": "./src/executable/typia.ts"
  },
  "ttsc": {
    "plugin": {
      "transform": "typia/lib/transform"
    }
  },
  "scripts": {
    "build": "rimraf lib && ttsc && rolldown -c && cp ../../README.md README.md",
    "dev": "ttsc --watch",
    "prepack": "pnpm run build"
  },
  "repository": {
    "type": "git",
    "url": "https://github.com/samchon/typia"
  },
  "author": "Jeongho Nam",
  "license": "MIT",
  "bugs": {
    "url": "https://github.com/samchon/typia/issues"
  },
  "homepage": "https://typia.io",
  "dependencies": {
    "@standard-schema/spec": "^1.0.0",
    "@typia/interface": "workspace:^",
    "@typia/utils": "workspace:^",
    "commander": "^10.0.0",
    "inquirer": "^8.2.5",
    "randexp": "^0.5.3",
    "tinyglobby": "^0.2.12"
  },
  "peerDependencies": {
    "@ttsc/unplugin": ">=0.19.2",
    "ttsc": ">=0.19.2"
  },
  "peerDependenciesMeta": {
    "@ttsc/unplugin": {
      "optional": true
    },
    "ttsc": {
      "optional": true
    }
  },
  "devDependencies": {
    "@types/inquirer": "^8.2.5",
    "@types/node": "catalog:utils",
    "chalk": "^4.0.0",
    "rimraf": "catalog:utils",
    "rolldown": "catalog:rolldown",
    "suppress-warnings": "^1.0.2",
    "ttsc": "catalog:typescript",
    "typescript": "catalog:typescript"
  },
  "sideEffects": false,
  "files": [
    "README.md",
    "package.json",
    "lib",
    "native",
    "src"
  ],
  "keywords": [
    "fast",
    "json",
    "stringify",
    "transform",
    "ajv",
    "io-ts",
    "zod",
    "schema",
    "json-schema",
    "generator",
    "assert",
    "clone",
    "is",
    "validate",
    "equal",
    "runtime",
    "type",
    "typebox",
    "checker",
    "validator",
    "safe",
    "parse",
    "prune",
    "random",
    "protobuf",
    "llm",
    "llm-function-calling",
    "structured-output",
    "openai",
    "chatgpt",
    "claude",
    "gemini",
    "llama"
  ],
  "packageManager": "pnpm@10.6.4",
  "publishConfig": {
    "access": "public",
    "types": "lib/index.d.ts",
    "main": "lib/index.js",
    "module": "lib/index.mjs",
    "bin": {
      "typia": "./lib/executable/typia.js"
    },
    "exports": {
      ".": {
        "types": "./lib/index.d.ts",
        "import": "./lib/index.mjs",
        "default": "./lib/index.js"
      },
      "./lib/module": {
        "types": "./lib/index.d.ts",
        "import": "./lib/index.mjs",
        "default": "./lib/index.js"
      },
      "./lib/transform": {
        "types": "./lib/transform.d.ts",
